 184→router.get('/getFollowsData', async(req, res) => {
 185→    const {userId, loggedInUserId} = req.query;
 186→    if(!userId && !loggedInUserId) return res.status(400).json({error: 'userId or loggendUserId is undefined '});
 187→    // console.log(req.query)
 188→    try {
 189→        const followersCountPromise = supabase
 190→        .from('follows')
 191→        .select('*', {count: 'exact', head: true})
 192→        .eq('following_id', userId);
 193→
 194→        const followingCountPromise = supabase
 195→        .from('follows')
 196→        .select('*', {count: 'exact', head: true})
 197→        .eq('follower_id', userId)
 198→
 199→        const isFollowingPromise = supabase
 200→        .from('follows')
 201→        .select('*', {count: 'exact', head: true})
 202→        .eq('follower_id', loggedInUserId)
 203→        .eq('following_id', userId)
 204→
 205→        const [followersCountResult, followingsCountResult, isFollowingResult] = await Promise.all([
 206→            followersCountPromise, followingCountPromise, isFollowingPromise,
 207→        ])
 208→
 209→
 210→        const {count: followersCount, error: errorFollowers } = followersCountResult;
 211→        const {count: followingsCount, error: errorFollowings} = followingsCountResult;
 212→        const {count: isFollowingCount, error: errorIsfollowing} = isFollowingResult;
 213→
 214→        if(errorFollowers || errorFollowings || errorIsfollowing){
 215→            console.error('supabase error while fetching data:', errorFollowers.message, errorFollowings.message, errorIsfollowing.message)
 216→            return res.status(500).json({error: 'failed to fetch data'})
 217→        }
 218→
 219→        return res.status(200).json({
 220→            followersCount: followersCount,
 221→            followingsCount: followingsCount,
 222→            isFollowing: isFollowingCount > 0
 223→        })
 224→
 225→    } catch (error) {
 226→        console.error('Error in Promise.all:', error);
 227→        res.status(500).json({ error: 'An unexpected error occurred' });
 228→    }
 229→
 230→})
