100→const extractFromLexical = (contentJson) => {
101→    try {
102→        const parsed = typeof contentJson === 'string' ? JSON.parse(contentJson) : contentJson;
103→        const texts = [];
104→        let firstImage = null;
105→
106→        const walk = (node) => {
107→            if (!node || typeof node !== 'object') return;
108→
109→            const nodeType = String(node.type || node.__type || '').trim().toLowerCase();
110→            if (nodeType === 'text' && typeof node.text === 'string') {
111→                texts.push(node.text);
112→            }
113→
114→            const isImageNode = nodeType === 'image' || nodeType.endsWith('image') || nodeType.includes('image');
115→            if (!firstImage && isImageNode) {
116→                const image = imageFromNodeLike(node);
117→                if (image) {
118→                    firstImage = image;
119→                }
120→            }
121→
122→            if (Array.isArray(node.children)) {
123→                node.children.forEach(walk);
124→            }
125→        };
126→
127→        if (parsed?.root) {
128→            walk(parsed.root);
129→        }
130→
131→        return {
132→            text: normalizeWhitespace(texts.join(' ')),
133→            image: firstImage
134→        };
135→    } catch {
136→        return { text: '', image: null };
137→    }
138→};
